import{_ as e,o as i,c as t,a2 as s}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Configuración de página","description":"","frontmatter":{},"headers":[],"relativePath":"es/Page/page-settings.md","filePath":"es/Page/page-settings.md","lastUpdated":1781962217000}'),n={name:"es/Page/page-settings.md"};function d(o,a,r,l,c,p){return i(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="configuracion-de-pagina" tabindex="-1">Configuración de página <a class="header-anchor" href="#configuracion-de-pagina" aria-label="Permalink to &quot;Configuración de página&quot;">​</a></h1><p>La configuración de página controla elementos básicos de presentación, páginas públicas y experiencia de subida en ImgBed.</p><h2 id="donde-se-configura" tabindex="-1">Dónde se configura <a class="header-anchor" href="#donde-se-configura" aria-label="Permalink to &quot;Dónde se configura&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configuración del sistema -&gt; Configuración de página</span></span></code></pre></div><h2 id="ajustes-principales" tabindex="-1">Ajustes principales <a class="header-anchor" href="#ajustes-principales" aria-label="Permalink to &quot;Ajustes principales&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ajuste</th><th>Descripción</th></tr></thead><tbody><tr><td>Nombre del sitio</td><td>Se usa en el título del navegador y en la interfaz</td></tr><tr><td>Descripción del sitio</td><td>Texto descriptivo del sitio</td></tr><tr><td>Logotipo / icono</td><td>Imágenes usadas en la página y el navegador</td></tr><tr><td>Imagen de fondo</td><td>Fondo de la página principal</td></tr><tr><td>Pie de página</td><td>Copyright, enlaces externos u otra información</td></tr><tr><td>Texto de subida</td><td>Mensaje mostrado en el área de subida</td></tr></tbody></table><h2 id="paginas-publicas" tabindex="-1">Páginas públicas <a class="header-anchor" href="#paginas-publicas" aria-label="Permalink to &quot;Páginas públicas&quot;">​</a></h2><p>Si usas páginas para visitantes, revisa también los directorios públicos, el modo de acceso y el modo de carga de imágenes.</p><p>Especialmente con la galería pública o la API de imagen aleatoria, la configuración de página debe ir acompañada de los permisos de publicación en Otros ajustes.</p><h2 id="despues-de-guardar" tabindex="-1">Después de guardar <a class="header-anchor" href="#despues-de-guardar" aria-label="Permalink to &quot;Después de guardar&quot;">​</a></h2><ol><li>Guarda los cambios.</li><li>Recarga la página principal.</li><li>Comprueba la vista en escritorio y en móvil.</li><li>Verifica que logotipo, fondo, descripción y enlaces del pie se muestren como esperas.</li></ol><p>Si una imagen no se actualiza, comprueba que su URL se pueda abrir y que el navegador no esté usando caché antigua.</p>',12)])])}const h=e(n,[["render",d]]);export{g as __pageData,h as default};
